import './App.css';
import BlogList from './components/BlogList.jsx';
import Header from './components/Header.jsx';
import {BrowserRouter,Route,Switch} from "react-router-dom";

function App() {
  return (

    <BrowserRouter>
      <Switch>
        <Route index element={
          <div>
            <Header></Header>
            <main className="container mt-5 d-flex justify-content-center">
                <BlogList></BlogList>
            </main>
        </div>
        }/>
      </Switch>
    </BrowserRouter>
  );
}

export default App;
